class Solution:
    def maxArea(self, h: list[int]) -> int:
        i, j, best = 0, len(h) - 1, 0      # 左右指针放两端,best 存最大面积
        while i < j:
            # 面积 = 底(j - i) × 高(两根线里较矮的那根)
            best = max(best, (j - i) * min(h[i], h[j]))
            if h[i] < h[j]:                # 谁矮就移动谁:矮的一边限制了高度
                i += 1
            else:
                j -= 1
        return best
